arguments.argument:
event_inherited()
if alertNotice>0 //Alert Icon
{
  draw_sprite_ext(sC_AlertNotice,0,x,y-24,alertNScale,alertNScale,0,c_white,1)
  
  if alertNotice=1
  {
    alertNScale+=0.2
    if alertNScale=1 {alertNotice=2}
  }
  else if alertNotice>=2
  {
    alertNotice+=1
    if alertNotice>=15 {alertNotice=0}
  }
}
